query:
SELECT COUNT(*) as total_carousel_images FROM background_images;
SELECT COUNT(*) as total_carousel_slides FROM carousel_slides;
SELECT bi.id, bi.userId, bi.carouselSlideId, bi.duration, bi.order, cs.titulo, cs.urlMedia FROM background_images bi LEFT JOIN carousel_slides cs ON bi.carouselSlideId = cs.id LIMIT 10;

